def priority(job, proc_times, sequence):
    # Heuristic: Congestion-Aware Large-Job-First (CALJF)
    ALPHA = 1.0
    BETA = 1.0
    EPS = 1e-9

    if not proc_times:
        return float('-inf')

    n = len(proc_times)
    m = len(proc_times[0])

    # Basic shape check
    for row in proc_times:
        if len(row) != m:
            raise ValueError("proc_times must be a rectangular matrix")

    scheduled = set(sequence)
    remaining = [j for j in range(n) if j not in scheduled]

    if job not in remaining:
        return float('-inf')

    # Compute downstream sums S_k for k=1..m-1 (machines 2..m)
    S_k = [0.0] * max(0, m - 1)
    for i in remaining:
        row = proc_times[i]
        for k in range(1, m):
            S_k[k - 1] += row[k]
    S_total = sum(S_k)

    # Compute I_j for all remaining jobs
    I_vals = {}
    for j in remaining:
        W_j = sum(proc_times[j])
        downstream_contrib = 0.0
        row_j = proc_times[j]
        for k in range(1, m):
            downstream_contrib += row_j[k] * (1.0 + (S_k[k - 1] / (S_total + EPS)))
        I_j = ALPHA * W_j + BETA * downstream_contrib
        I_vals[j] = I_j

    return I_vals[job]
